pipeline {
    agent none
    options {
        timestamps()
    }
    environment {
        CURRENT_DATE = "${params.timeformat ? params.timeformat : new Date().format('yyyyMMdd-HHmmss')}"
    }
    stages {
        stage('get_obj_token') {
            agent { node { label "yidian_agent_puyullm_gpu_data_management" } }
            steps {
                script {
                    def obj_token = sh(script: """
                        cd /home/puyudelivery/code/data_submission_yidian
                        python get_obj_token.py
                    """, returnStdout: true).trim()
                    // 更新环境变量
                    env.OBJ_TOKEN = obj_token
                    // 使用环境变量
                    echo "OBJ_TOKEN: ${env.OBJ_TOKEN}"
                }
            }
        }
        stage('get_server_time') {
            agent { node { label 'yidian_agent_puyullm_gpu_data_management' } }
            steps {
                script {
                    // 使用 shell 命令获取服务器时间并解析 JSON 响应
                    def response = sh(script: """
                        export http_proxy=http://tanghuanze:jqr80FWBRDuSIVcGoUfNGWOgBu4nbH6EgfxpEW1f8IKxXyEWDIL0UNFD8m5I@10.1.20.50:23128
                        export https_proxy=http://tanghuanze:jqr80FWBRDuSIVcGoUfNGWOgBu4nbH6EgfxpEW1f8IKxXyEWDIL0UNFD8m5I@10.1.20.50:23128
                        curl -s https://f.m.suning.com/api/ct.do
                    """, returnStdout: true).trim()
                    // 输出响应内容以便调试
                    echo "Response 1: ${response}"
                    def jsonResponse = new groovy.json.JsonSlurper().parseText(response)
                    echo "Response 2: ${jsonResponse}"
                    def serverTimeMillis = jsonResponse['currentTime'] // 提取时间字段
                    echo "Response 3: ${serverTimeMillis}"
                    // 将毫秒转换为秒（UNIX 时间戳）
                    def serverTimeSeconds = (int) (serverTimeMillis / 1000)
                    echo "Response 4: ${serverTimeSeconds}"
                    // 更新环境变量 CURRENT_OFFICIAL_TIME
                    env.CURRENT_OFFICIAL_TIME = serverTimeSeconds.toString()
                    echo "Current official Beijing time JSON: ${env.CURRENT_OFFICIAL_TIME}"
                }
            }
        }
        stage('write_one_new_feishu_record') {
            agent { node { label 'spark_intern_new_2026platform' } }
            options {
                timeout(time: 300, unit: 'MINUTES') // timeout on this stage
            }
            steps {
                dir('/tmp/jenkins/') {
                    script {
                        // Validate required parameters
                        def requiredParams = [
                            'dryrun', 'specific_project', 'ability_dimension', 'domain',
                            'subset_name', 'language_name', 'data_version', 'data_format_type',
                            'input_data_path', 'provider_name', 'training_stage',
                            'cot_type', 'data_description'
                        ]
                        requiredParams.each { param ->
                            if (!params."${param}") {
                                error("${param} must be filled in!")
                            }
                        }
                        // Use the server time JSON string
                        def serverTimeJson = env.CURRENT_OFFICIAL_TIME
                        echo "Server time JSON: ${serverTimeJson}"
                        try {
                            sh """
                            cd /home/tanghuanze/intern_delivery/data_management_pipeline/stages/stage1_waitlist
                            python write_one_new_feishu_record.py \
                            --dryrun $params.dryrun\
                            --specific_project $params.specific_project\
                            --ability_dimension $params.ability_dimension\
                            --big_domain_name $params.domain\
                            --subset_name $params.subset_name\
                            --language_name $params.language_name\
                            --data_version $params.data_version\
                            --data_format_type $params.data_format_type\
                            --input_data_path $params.input_data_path\
                            --input_multi_modal_elements_path $params.input_multi_modal_elements_path\
                            --provider_name $params.provider_name\
                            --attr_path $params.attr_path\
                            --attr_version $params.attr_version\
                            --attr_name_list $params.attr_name_list\
                            --training_stage $params.training_stage\
                            --data_description $params.data_description\
                            --cot_type $params.cot_type\
                            --data_label $params.data_label\
                            --current_unix_timestamp ${env.CURRENT_OFFICIAL_TIME}\
                            --build_number ${env.BUILD_NUMBER}\
                            --obj_token ${env.OBJ_TOKEN}\
                            --others $params.others
                        """
                        } catch (e) {
                            echo "Error occurred!"
                            echo "${e}"
                            throw new Exception("Show write_one_new_feishu_record Error")
                        }
                    }
                }
            }
        }
    }
}

